example.code:
use proptest::prelude::*;

// Invariant: decode(encode(input)) == input for all valid inputs
proptest! {
    #[test]
    fn encode_decode_roundtrip(s in "[a-zA-Z0-9 ]{0,100}") {
        let encoded = encode(&s);
        let decoded = decode(&encoded).expect("decode should succeed for valid encoded input");
        prop_assert_eq!(decoded, s);
    }

    #[test]
    fn sorted_output_is_monotone(mut v in prop::collection::vec(0i32..=1000, 0..50)) {
        v.sort();
        for window in v.windows(2) {
            prop_assert!(window[0] <= window[1]);
        }
    }
}

proptest! {
    #[test]
    fn sum_is_symmetric(a in 0.0f64..1.0, b in 0.0f64..1.0) {
        assert_eq!(a + b, b + a); // may flake on NaN or denormals
    }
}
